const childProcess = require('child_process');
const fs = require('fs');

// Set environment variables
process.env.NODE_ENV = 'production';

// Install dependencies
childProcess.execSync(`npm install`, { stdio: 'inherit' });

// Run tests
childProcess.execSync(`npm run test`, { stdio: 'inherit' });

// Build application
childProcess.execSync(`npx webpack --mode production`, { stdio: 'inherit' });

// Deploy to production
fs.copyFileSync('dist/index.html', '/var/www/html/index.html');
fs.copyFileSync('dist/style.css', '/var/www/html/style.css');

console.log('Deployment completed successfully.');